enum Environment {
    DEVELOPMENT("https://dev.api.example.com/"),
    STAGING("https://staging.api.example.com/"),
    PRODUCTION("https://api.example.com/");

    private final String baseUrl;

    Environment(String baseUrl) {
        this.baseUrl = baseUrl;
    }

    public String baseUrl() {
        return baseUrl;
    }

    public static Environment current() {
        String value = System.getProperty("app.env");
        if (value == null || value.trim().isEmpty()) {
            value = System.getenv("APP_ENV");
        }
        if (value == null) {
            return PRODUCTION;
        }
        value = value.trim().toLowerCase();
        if ("dev".equals(value) || "development".equals(value)) {
            return DEVELOPMENT;
        }
        if ("stage".equals(value) || "staging".equals(value)) {
            return STAGING;
        }
        return PRODUCTION;
    }
}

final class ServiceLocator {
    private static volatile ApiService apiService;

    private ServiceLocator() {
    }

    public static ApiService provideApiService(Context context) {
        if (apiService == null) {
            synchronized (ServiceLocator.class) {
                if (apiService == null) {
                    apiService = createRetrofit(context).create(ApiService.class);
                }
            }
        }
        return apiService;
    }

    private static Retrofit createRetrofit(Context context) {
        OkHttpClient client = createOkHttpClient(context);
        return new Retrofit.Builder()
                .baseUrl(Environment.current().baseUrl())
                .client(client)
                .addConverterFactory(GsonConverterFactory.create())
                .build();
    }

    private static OkHttpClient createOkHttpClient(Context context) {
        HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor();
        loggingInterceptor.setLevel(Environment.current() == Environment.PRODUCTION
                ? HttpLoggingInterceptor.Level.NONE
                : HttpLoggingInterceptor.Level.BODY);

        return new OkHttpClient.Builder()
                .connectTimeout(15, TimeUnit.SECONDS)
                .readTimeout(15, TimeUnit.SECONDS)
                .writeTimeout(15, TimeUnit.SECONDS)
                .addInterceptor(new BaseUrlInterceptor(Environment.current().baseUrl()))
                .addInterceptor(loggingInterceptor)
                .build();
    }
}

final class BaseUrlInterceptor implements Interceptor {
    private final String baseUrl;

    BaseUrlInterceptor(String baseUrl) {
        this.baseUrl = baseUrl;
    }

    @NonNull
    @Override
    public Response intercept(@NonNull Chain chain) throws IOException {
        Request original = chain.request();
        HttpUrl originalUrl = original.url();
        HttpUrl base = HttpUrl.parse(baseUrl);
        if (base == null) {
            return chain.proceed(original);
        }
        HttpUrl newUrl = originalUrl.newBuilder()
                .scheme(base.scheme())
                .host(base.host())
                .port(base.port())
                .build();
        Request newRequest = original.newBuilder().url(newUrl).build();
        return chain.proceed(newRequest);
    }
}

